from agent import *from models.products import *import reXCAT = ['alphabetische Spiele Tests', 'Hardware']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.browser.use_new_parser = True    session.queue(Request('https://www.gamefeature.de/'), process_frontpage, {})def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//ul[@class="g-sublevel"]/li[contains(@class, "g-menu-item")]/a[contains(., "Test")]')    for cat in cats:        name = cat.xpath('.//span[@class="g-menu-item-title"]/text()').string()        url = cat.xpath('@href').string()        if name not in XCAT:            name = name.replace('Tests', '').replace('Neuste', '').strip()            session.queue(Request(url), process_revlist, dict(cat=name))def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//th[@class="list-title"]/a')    for rev in revs:        title = rev.xpath('text()').string()        url = rev.xpath('@href').string()        session.queue(Request(url), process_review, dict(context, title=title, url=url))    next_url = data.xpath('//li[@class="page-item"]/a[contains(@aria-label, "nächsten")]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, context)def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['title'].replace('Hardware Test', '').replace('PC Test', '').replace('3DS Test', '').replace('im Test', '').replace('im Xbox One Test', '').replace('PS4 Test', '').strip()    if product.name.split()[-1] == 'Test':        product.name = product.name.rsplit(' Test', 1)[0]    product.url = data.xpath('//a[contains(., "kaufen")]/@href').string() or context['url']    product.category = context['cat'].replace('Reviews', '').strip('| ')    product.ssid = context['url'].split('/')[-1].split('-')[0]    review = Review()    review.title = context['title']    review.url = context['url']    review.ssid = product.ssid    review.type = 'pro'    review.date = data.xpath('//tr[contains(., "Erscheinungsdatum")]/td[last()]/text()').string()    pros = data.xpath('//p/span[preceding-sibling::span[regexp:test(., "PRO", "i")]]/text()').strings()    if not pros:        pros = data.xpath('//table[thead[contains(., "CONTRA")]]/tbody/tr/td[1]/p//text()[not(.="+")]').strings()    if not pros:        pros = data.xpath('//table/tbody[contains(., "CONTRA")]/tr/td[span[contains(@style, "background-color") and contains(., "+")]]/span[not(contains(@style, "background-color") and contains(., "+"))]/text()').strings()    if not pros:        pros = data.xpath('//td/p[contains(., "PRO")]/following-sibling::*[self::p or self::div][contains(., "+")]//text()').strings()    if not pros:        pros = data.xpath('//td/p/strong[contains(., "PRO")]/following-sibling::*[self::p or self::div or self::span][contains(., "+")]//text()').strings()    if pros:        for pro in pros:            pro = pro.strip('  .,+-…\n\t')            if pro:                review.properties.append(ReviewProperty(type=ReviewPropertyType(name='pros'), value=pro, name="Pro"))    cons = data.xpath('//p/span[preceding-sibling::span[regexp:test(., "CONTRA", "i")]]/text()').strings()    if not cons:        cons = data.xpath('//table[thead[contains(., "CONTRA")]]/tbody/tr/td[2]/p//text()[not(.="-")]').strings()    if not cons:        cons = data.xpath('//table/tbody[contains(., "CONTRA")]/tr/td[span[contains(@style, "background-color") and contains(., "-")]]/span[not(contains(@style, "background-color") and contains(., "-"))]/text()').strings()    if not cons:        cons = data.xpath('//td/p[contains(., "CONTRA")]/following-sibling::*[self::p or self::div][contains(., "-")]//text()').strings()    if not cons:        cons = data.xpath('//td/p/strong[contains(., "CONTRA")]/following-sibling::*[self::p or self::div or self::span][contains(., "-")]//text()').string()    if cons:        for con in cons:            con = con.strip('  .,+-…\n\t')            if con:                review.properties.append(ReviewProperty(type=ReviewPropertyType(name='cons'), value=con, name="Contra"))    grades = data.xpath('//div[@class="cw-rating-parts"]/div[not(contains(., "GESAMT"))]')    for grade in grades:        grade_name = grade.xpath('span[@class="cw-rating-label"]/text()').string()        grade_value = grade.xpath('@data-rating').string()        if grade_name and grade_value:            review.grades.append(Grade(name=grade_name, value=float(grade_value), best=100.0))    grade_overall = data.xpath('//div[@class="cw-rating-sum"]/div/@data-rating').string()    if not grade_overall:        grade_overall = data.xpath('//div[@class="cw-rating-parts"]/div/@data-rating').string()    if not grade_overall:        grade_overall = data.xpath('//div[h3[contains(., "Wertungsbereich")]]/p/span/text()').string()    if not grade_overall:        grade_overall = data.xpath('//p[regexp:test(., "UNSERE WERTUNG:", "i")]/following-sibling::*[1][contains(., "%")]//text()').string(multiple=True)    if grade_overall:        grade_overall = grade_overall.strip(' -%')        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=100.0))    conclusion = data.xpath('//h3[regexp:test(., "Fazit")]/following-sibling::p//text()').string(multiple=True)    if not conclusion:        conclusion = data.xpath('//td[p[contains(., "Offizielle Produktbeschreibung:")]]/div/*[self::div or self::p]//span[preceding::*[regexp:test(., "Fazit:", "i")]]//text()').string(multiple=True)    if conclusion:        conclusion = remove_emoji(conclusion).strip()        if conclusion:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='conclusion'), value=conclusion, name="Fazit"))    excerpt = data.xpath('//div[contains(@class, "article__body")]/div[div[contains(., "Offizielle Produktbeschreibung")]]/div[not(contains(., "Offizielle Produktbeschreibung"))]//text()[not(ancestor::*[self::ul or self::style or self::script or self::a[contains(@href, "spotify")] or self::div[contains(@class, "slideshow")]])]').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//td[p[contains(., "Offizielle Produktbeschreibung:")]]/div/*[self::p or self::div]//span[not(preceding::*[regexp:test(., "Fazit:", "i")] or regexp:test(., "Fazit:", "i"))]//text()').string()    if not excerpt:        excerpt = data.xpath('//div[contains(@class, "article__body")]/p[preceding-sibling::p[contains(., "Offizielle Produktbeschreibung")]]//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//div[contains(@class, "article__body")]/div[preceding-sibling::p[contains(., "Offizielle Produktbeschreibung") or contains(., "für GameFeature.de")]]//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//div[contains(@class, "article__body")]/p//text()[not(regexp:test(., "für GameFeature.de", "i") or contains(., "{audio}"))]').string(multiple=True)    if excerpt:        excerpt = remove_emoji(excerpt).replace('&', '&').strip()        if excerpt:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))            product.reviews.append(review)            session.emit(product)